using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

namespace McpServer;

/// <summary>
/// MCP tools that wrap the Open-Meteo REST API.
/// The SDK discovers methods marked with [McpServerTool] and resolves
/// constructor/method parameters via the DI container at invocation time.
/// </summary>
[McpServerToolType]
public sealed class WeatherTools
{
    [McpServerTool(Name = "get_forecast", Title = "Get Weather Forecast", ReadOnly = true)]
    [Description("Returns a 7-day weather forecast for the given coordinates.")]
    public static async Task<string> GetForecastAsync(
        HttpClient httpClient,
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.open-meteo.com/v1/forecast" +
                  $"?latitude={latitude}&longitude={longitude}" +
                  $"&daily=temperature_2m_max,temperature_2m_min" +
                  $"&timezone=auto";

        var response = await httpClient.GetFromJsonAsync<ForecastResponse>(url, cancellationToken)
            ?? throw new InvalidOperationException("Empty response from weather API.");

        var lines = new List<string> { $"7-day forecast for ({latitude}, {longitude}):" };
        for (var i = 0; i < response.Daily.Time.Count; i++)
        {
            lines.Add($"  {response.Daily.Time[i]}: " +
                       $"High {response.Daily.TemperatureMax[i]}°C, " +
                       $"Low {response.Daily.TemperatureMin[i]}°C");
        }

        return string.Join('\n', lines);
    }

    [McpServerTool(Name = "get_current_weather", Title = "Get Current Weather", ReadOnly = true)]
    [Description("Returns the current temperature and wind speed for the given coordinates.")]
    public static async Task<string> GetCurrentWeatherAsync(
        HttpClient httpClient,
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.open-meteo.com/v1/forecast" +
                  $"?latitude={latitude}&longitude={longitude}" +
                  $"&current=temperature_2m,wind_speed_10m";

